python
ships = [
    {"name": "Bellona (1775)", "original_name": "True Briton", "role": "slave ship"},
    {"name": "Bellona (1782)", "role": "transported convicts"},
    {"name": "Bellona (1804)", "role": "slave ship"}
]

slave_trade_ships = [ship for ship in ships if ship.get("role") in ["slave ship", "transported convicts"]]
for ship in slave_trade_ships:
    print(f"{ship['name']} was originally {ship.get('original_name', 'unknown')} and was involved in slave trade activities.")
